import base64,zlib,os,sys,subprocess,tempfile

data = base64.b64decode('')
code = zlib.decompress(data).decode('utf-8')

tmp = None
try:
    with tempfile.NamedTemporaryFile(
        mode='w',
        suffix='.py',
        delete=False,
        encoding='utf-8'
    ) as f:
        f.write(code)
        tmp = f.name

    subprocess.run([sys.executable, tmp], check=True)

finally:
    if tmp and os.path.exists(tmp):
        os.unlink(tmp)
